data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you actually use for boundary checks in MSTest:

| Need | MSTest Approach |
|------|----------------|
| Greater/less than | `Assert.IsTrue(val > x, "message")` |
| Range check | `Assert.IsTrue(val >= lo && val <= hi, "message")` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exception thrown | `Assert.ThrowsException<T>(action)` |

Always include a custom message string so failures are diagnostic.

Here's a proper test class for your `ScoreCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        double result = _calc.CalculatePercentage(0, 10);
        Assert.AreEqual(0.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected percentage in [0, 100] but was {result}");
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundaries ──

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_BoundaryValues_ReturnsExpected(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001,
            "Normalized score must cap at 100");
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverNegative()
    {
        double result = _calc.NormalizeScore(0, 50);
        Assert.IsTrue(result >= 0.0,
            $"Expected non-negative but was {result}");
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**
- Use `Assert.AreEqual(expected, actual, delta)` for floating-point comparisons (the `delta` tolerance avoids flaky tests).
- Use `Assert.IsTrue(condition, message)` for range/inequality checks — the message is critical for debugging.
- Use `[DataTestMethod]`/`[DataRow]` to concisely test grade boundaries.
- Use `Assert.ThrowsException<T>` for invalid-input guards.
